{
  "name": "@belt/tools",
  "version": "0.1.0",
  "description": "TypeScript utility library with runtime type validation, state management, and common helpers",
  "type": "module",
  "main": "./dist/index.cjs",
  "module": "./dist/index.js",
  "types": "./dist/index.d.ts",
  "exports": {
    ".": {
      "types": "./dist/index.d.ts",
      "import": "./dist/index.js",
      "require": "./dist/index.cjs"
    }
  },
  "files": [
    "dist",
    "README.md",
    "LICENSE"
  ],
  "scripts": {
    "build": "tsup",
    "dev": "tsup --watch",
    "typecheck": "tsc --noEmit",
    "test": "vitest",
    "test:watch": "vitest --watch",
    "coverage": "vitest --coverage"
  },
  "repository": {
    "type": "git",
    "url": "https://github.com/antoniopresto/belt.git",
    "directory": "packages/tools"
  },
  "keywords": [
    "typescript",
    "utilities",
    "validation",
    "state-management",
    "type-safe"
  ],
  "author": "Antonio Presto",
  "license": "MIT",
  "peerDependencies": {
    "react": ">=18.0.0"
  },
  "peerDependenciesMeta": {
    "react": {
      "optional": true
    }
  },
  "dependencies": {
    "date-fns": "^4.1.0",
    "immer": "^10.2.0",
    "lodash": "^4.17.21",
    "lru-cache": "^11.2.2",
    "minimatch": "^10.1.1",
    "typebox": "^1.0.50"
  },
  "devDependencies": {
    "@types/lodash": "^4.17.20",
    "@types/node": "^22.10.2",
    "@types/react": "^19.1.0",
    "tsup": "^8.3.0",
    "typescript": "^5.9.3",
    "vitest": "^4.0.8"
  }
}

